std::string simplify(const std::string& Str) {
    int Len = Str.length();
    std::vector<char> res(Len);
    int index = 0;
    int i = 0;
    std::stack<int> s;
    s.push(0);
    while (i < Len) {
        if (Str[i] == '+') {
            if (s.top() == 1) {
                res[index] = '-';
                index++;
            }
            if (s.top() == 0) {
                res[index] = '+';
                index++;
            }
        }
        else if (Str[i] == '-') {
            if (s.top() == 1) {
                res[index] = '+';
                index++;
            }
            else if (s.top() == 0) {
                res[index] = '-';
                index++;
            }
        }
        else if (Str[i] == '(' && i > 0) {
            if (Str[i - 1] == '-') {
                int x = (s.top() == 1) ? 0 : 1;
                s.push(x);
            }
            else if (Str[i - 1] == '+') {
                s.push(s.top());
            }
        }
        else if (Str[i] == ')') {
            s.pop();
        }
        else {
            res[index] = Str[i];
            index++;
        }
        i++;
    }
    return std::string(res.begin(), res.begin() + index);
}

