int maxSubArraySum(std::vector<int>& a) {
    int size = a.size();
    int max_so_far = std::numeric_limits<int>::min();
    int max_ending_here = 0;
    int start = 0;
    int end = 0;
    int s = 0;
    for (int i = 0; i < size; i++) {
        max_ending_here += a[i];
        if (max_so_far < max_ending_here) {
            max_so_far = max_ending_here;
            start = s;
            end = i;
        }
        if (max_ending_here < 0) {
            max_ending_here = 0;
            s = i + 1;
        }
    }
    return (end - start + 1);
}

