int KnapSack(std::vector<int>& val, std::vector<int>& wt, int n, int W) {
    std::vector<std::vector<int>> mat(2, std::vector<int>(W + 1, 0));
    int i = 0;
    while (i < n) {
        int j = 0;
        if (i % 2 == 0) {
            while (j < W) {
                j++;
                if (wt[i] <= j && j - wt[i] < W) {
                    mat[1][j] = std::max(val[i] + mat[0][j - wt[i]], mat[0][j]);
                } else {
                    mat[1][j] = mat[0][j];
                }
            }
        } else {
            while (j < W) {
                j++;
                if (wt[i] <= j && j - wt[i] < W) {
                    mat[0][j] = std::max(val[i] + mat[1][j - wt[i]], mat[1][j]);
                } else {
                    mat[0][j] = mat[1][j];
                }
            }
        }
        i++;
    }
    if (n % 2 == 0) {
        return mat[0][W];
    } else {
        return mat[1][W];
    }
}

