bool isMultipleOf3(int n) {
    int odd_count = 0;
    int even_count = 0;
    if (n < 0) {
        n = -n;
    }
    if (n == 0) {
        return true;
    }
    if (n == 1) {
        return false;
    }
    while (n) {
        if (n & 1) {
            odd_count += 1;
        }
        if (n & 2) {
            even_count += 1;
        }
        n >>= 2;
    }
    return isMultipleOf3(std::abs(odd_count - even_count));
}

